%% =========================================================================
% P4_Exp07_LFP_SOH_Label_Cost_Sensitivity.m
%
% Purpose:
% This script evaluates how the unit cost of acquiring one target-pack SOH
% label changes the optimal number of labelled target packs, k*, and the
% resulting fixed-scale LFP recertification cost.
%
% The script reuses the k-dependent decision-loss curves generated by the
% Part4 Exp01. It does not rerun Monte Carlo simulation or the
% threshold-grid search because, conditional on k, the SOH-labelling cost
% and fixed model-adaptation cost do not depend on T1 or T2. Therefore, the
% thresholds T1*(k) and T2*(k) optimized in Exp01 remain valid when only the
% unit SOH-label cost is varied.
%
% Required upstream file:
% P4_Exp01_FixedScale_LFP_Results.mat
%
% Figure outputs:
% Extended Data Fig. 6c:
% optimal k* and total cost per pack versus unit SOH-label cost
% Extended Data Fig. 6d:
% optimized cost decomposition versus unit SOH-label cost
%% =========================================================================

clear;
clc;
close all;

set(groot, 'DefaultFigureVisible', 'on');

%% 1) Configuration and path setup
cfg = struct();

script_dir = fileparts(mfilename('fullpath'));

if isempty(script_dir)
 script_dir = pwd;
end

cfg.part4_dir = script_dir;

cfg.output_dir = fullfile(cfg.part4_dir, 'Output');
cfg.results_dir = fullfile(cfg.output_dir, 'Results');

cfg.figure_root = fullfile(cfg.part4_dir, 'Figures');
cfg.extended_fig_dir = fullfile(cfg.figure_root, 'Extended');

% Prefer the structured result from Exp01.
cfg.input_result_primary = fullfile(cfg.results_dir, ...
 'P4_Exp01_FixedScale_LFP_Results.mat');

cfg.input_workspace_primary = fullfile(cfg.results_dir, ...
 'P4_Exp01_FixedScale_LFP_Workspace.mat');

% Legacy fallbacks.
cfg.input_result_legacy = fullfile(cfg.output_dir, ...
 'Result01_FixedScale_LFP_Results.mat');

cfg.input_workspace_legacy = fullfile(cfg.output_dir, ...
 'Result01_FixedScale_LFP_Workspace.mat');

% Output files.
cfg.summary_csv = fullfile(cfg.results_dir, ...
 'P4_Exp07_LFP_SOHLabelCostSensitivity_Summary.csv');

cfg.all_k_csv = fullfile(cfg.results_dir, ...
 'P4_Exp07_LFP_SOHLabelCostSensitivity_AllK.csv');

cfg.result_mat = fullfile(cfg.results_dir, ...
 'P4_Exp07_LFP_SOHLabelCostSensitivity_Results.mat');

% Extended Data Fig. 6c-d.
% Panels a-b are reserved for the fixed-k regret benchmarks.
cfg.fig_dual = fullfile(cfg.extended_fig_dir, ...
 'ExD06c_LFP_SOH_label_cost_sensitivity.fig');

cfg.png_dual = fullfile(cfg.extended_fig_dir, ...
 'ExD06c_LFP_SOH_label_cost_sensitivity.png');

cfg.fig_cost_decomp = fullfile(cfg.extended_fig_dir, ...
 'ExD06d_LFP_SOH_label_cost_decomposition.fig');

cfg.png_cost_decomp = fullfile(cfg.extended_fig_dir, ...
 'ExD06d_LFP_SOH_label_cost_decomposition.png');

cfg.png_resolution = 600;

% Unit SOH-label cost scenarios, USD per labelled target pack.
cfg.c_pack_list = (50:50:800)';

% Numerical checks.
cfg.accounting_tolerance_abs_USD = 1e-6;
cfg.accounting_tolerance_rel = 1e-9;

folder_list = { ...
 cfg.output_dir, ...
 cfg.results_dir, ...
 cfg.figure_root, ...
 cfg.extended_fig_dir};

for ii = 1:numel(folder_list)

 if ~exist(folder_list{ii}, 'dir')

 [status, message] = mkdir(folder_list{ii});

 if ~status
 error('Unable to create folder:\n%s\nReason: %s', ...
 folder_list{ii}, message);
 end
 end
end

%% 2) Locate and load the fixed-scale LFP result
[cfg.input_mat, cfg.input_type] = local_select_input_file(cfg);

fprintf('================ Part4 Exp07: LFP SOH-label cost sensitivity ================\n');
fprintf('Input file: %s\n', cfg.input_mat);
fprintf('Input type: %s\n', cfg.input_type);
fprintf('Summary CSV: %s\n', cfg.summary_csv);
fprintf('All-k CSV: %s\n', cfg.all_k_csv);
fprintf('Result MAT: %s\n', cfg.result_mat);
fprintf('Extended figure folder: %s\n', cfg.extended_fig_dir);

S = load(cfg.input_mat);

if isfield(S, 'LFP_fixed_result')
 R = S.LFP_fixed_result;
else
 R = S;
end

required_fields = { ...
 'k_vals', ...
 'O_base', ...
 'R_base', ...
 'T1_base', ...
 'T2_base', ...
 'Fixed_Scale_N', ...
 'c_train'};

local_require_fields(R, required_fields, cfg.input_mat);

% Exp01 uses H_base. A_base is accepted only as a legacy alias.
[H_base, handling_field_used] = local_get_first_existing_field( ...
 R, {'H_base', 'A_base'}, ...
 'Mismatch handling and rework cost per pack');

k_vals = double(R.k_vals(:));

O_base = double(R.O_base(:));
H_base = double(H_base(:));
R_base = double(R.R_base(:));

T1_base = double(R.T1_base(:));
T2_base = double(R.T2_base(:));

Fixed_Scale_N = double(R.Fixed_Scale_N);
c_train = double(R.c_train);

if isfield(R, 'c_pack')
 c_pack_baseline = double(R.c_pack);
else
 c_pack_baseline = 300;
 warning(['Baseline c_pack was not found in the Exp01 output. ' ...
 'Using 300 USD per labelled target pack.']);
end

n_k = numel(k_vals);

array_lengths = [ ...
 numel(O_base), ...
 numel(H_base), ...
 numel(R_base), ...
 numel(T1_base), ...
 numel(T2_base)];

if any(array_lengths ~= n_k)
 error('The loaded k-dependent arrays have inconsistent lengths.');
end

if any(~isfinite(k_vals)) || any(diff(k_vals) <= 0)
 error('k_vals must be finite and strictly increasing.');
end

if any(~isfinite(O_base)) || ...
 any(~isfinite(H_base)) || ...
 any(~isfinite(R_base))

 error('The loaded per-pack decision-cost curves contain non-finite values.');
end

if any(O_base < -1e-10) || ...
 any(H_base < -1e-10) || ...
 any(R_base < -1e-10)

 error('Decision-cost components must be non-negative.');
end

if ~isscalar(Fixed_Scale_N) || ...
 ~isfinite(Fixed_Scale_N) || ...
 Fixed_Scale_N <= 0

 error('Fixed_Scale_N must be a positive finite scalar.');
end

if ~isscalar(c_train) || ~isfinite(c_train) || c_train < 0
 error('c_train must be a non-negative finite scalar.');
end

if ~isscalar(c_pack_baseline) || ...
 ~isfinite(c_pack_baseline) || ...
 c_pack_baseline < 0

 error('The baseline c_pack must be a non-negative finite scalar.');
end

fprintf('>>> Fixed-scale LFP result loaded successfully.\n');
fprintf('>>> Handling-cost field used: %s\n', handling_field_used);
fprintf('>>> Evaluated k range: %d to %d (%d values).\n', ...
 min(k_vals), max(k_vals), n_k);
fprintf('>>> Fixed deployment scale: %.0f packs.\n', Fixed_Scale_N);
fprintf('>>> Baseline unit SOH-label cost: %.2f USD per labelled pack.\n', ...
 c_pack_baseline);
fprintf('>>> Fixed model-adaptation cost: %.2f USD.\n', c_train);

%% 3) Validate the baseline Exp01 cost accounting
Decision_loss_per_pack = O_base + H_base + R_base;
Decision_loss_total_by_k = Fixed_Scale_N .* Decision_loss_per_pack;

Baseline_labelling_cost_by_k = k_vals .* c_pack_baseline;
Baseline_adaptation_cost_by_k = c_train .* ones(n_k, 1);

Baseline_information_cost_by_k = ...
 Baseline_labelling_cost_by_k + ...
 Baseline_adaptation_cost_by_k;

Baseline_total_cost_rebuilt = ...
 Decision_loss_total_by_k + ...
 Baseline_information_cost_by_k;

if isfield(R, 'Fixed_Total_Cost')

 Fixed_Total_Cost_loaded = double(R.Fixed_Total_Cost(:));

 if numel(Fixed_Total_Cost_loaded) ~= n_k
 error('Fixed_Total_Cost has an inconsistent length.');
 end

 baseline_accounting_error = abs( ...
 Fixed_Total_Cost_loaded - ...
 Baseline_total_cost_rebuilt);

 baseline_accounting_tolerance = max( ...
 cfg.accounting_tolerance_abs_USD, ...
 cfg.accounting_tolerance_rel .* ...
 max(max(abs(Fixed_Total_Cost_loaded)), 1));

 if max(baseline_accounting_error) > baseline_accounting_tolerance

 error(['The loaded Exp01 total-cost curve is inconsistent with ' ...
 'O + H + R + k*c_pack + c_train.\n' ...
 'Maximum discrepancy = %.6g USD.\n' ...
 'Rerun the Part4 Exp01 before running Exp07.'], ...
 max(baseline_accounting_error));
 end

else

 Fixed_Total_Cost_loaded = Baseline_total_cost_rebuilt;
 baseline_accounting_error = zeros(n_k, 1);
 baseline_accounting_tolerance = NaN;
end

[baseline_total_cost_min, baseline_opt_idx_rebuilt] = ...
 min(Baseline_total_cost_rebuilt);

baseline_opt_k_rebuilt = k_vals(baseline_opt_idx_rebuilt);

if isfield(R, 'opt_k')

 baseline_opt_k_loaded = double(R.opt_k);

 if baseline_opt_k_loaded ~= baseline_opt_k_rebuilt

 error(['The baseline optimum reconstructed in Exp07 (k = %d) ' ...
 'does not match the Exp01 saved optimum (k = %d).\n' ...
 'Rerun the Part4 Exp01 before running Exp07.'], ...
 baseline_opt_k_rebuilt, baseline_opt_k_loaded);
 end

else

 baseline_opt_k_loaded = baseline_opt_k_rebuilt;
end

fprintf('>>> Baseline accounting check passed.\n');
fprintf('>>> Reconstructed baseline optimum: k* = %d, total cost = %.4f USD.\n', ...
 baseline_opt_k_rebuilt, baseline_total_cost_min);

%% 4) Define SOH-label cost scenarios
c_pack_list = unique( ...
 [double(cfg.c_pack_list(:)); c_pack_baseline], ...
 'sorted');

if any(~isfinite(c_pack_list)) || any(c_pack_list < 0)
 error('All unit SOH-label cost scenarios must be non-negative and finite.');
end

n_scenario = numel(c_pack_list);

%% 5) Recalculate k* under each unit SOH-label cost
k_star = zeros(n_scenario, 1);
T1_star = zeros(n_scenario, 1);
T2_star = zeros(n_scenario, 1);
opt_idx = zeros(n_scenario, 1);

Opportunity_loss_USD = zeros(n_scenario, 1);
Handling_rework_cost_USD = zeros(n_scenario, 1);
Risk_penalty_USD = zeros(n_scenario, 1);

SOH_labelling_cost_USD = zeros(n_scenario, 1);
Model_adaptation_cost_USD = zeros(n_scenario, 1);
Information_cost_USD = zeros(n_scenario, 1);

Decision_loss_total_USD = zeros(n_scenario, 1);
Total_cost_USD = zeros(n_scenario, 1);
Cost_per_pack_USD = zeros(n_scenario, 1);

Is_baseline_scenario = false(n_scenario, 1);
Is_k_on_search_boundary = false(n_scenario, 1);

TotalCost_byScenario_K = zeros(n_scenario, n_k);
InfoCost_byScenario_K = zeros(n_scenario, n_k);
DecisionLoss_byScenario_K = repmat( ...
 Decision_loss_total_by_k(:)', ...
 n_scenario, 1);

SOHLabelCost_byScenario_K = zeros(n_scenario, n_k);
AdaptationCost_byScenario_K = repmat( ...
 c_train .* ones(1, n_k), ...
 n_scenario, 1);

for ii = 1:n_scenario

 c_pack_now = c_pack_list(ii);

 SOH_labelling_cost_by_k = ...
 k_vals .* c_pack_now;

 Model_adaptation_cost_by_k = ...
 c_train .* ones(n_k, 1);

 Information_cost_by_k = ...
 SOH_labelling_cost_by_k + ...
 Model_adaptation_cost_by_k;

 Total_cost_by_k = ...
 Decision_loss_total_by_k + ...
 Information_cost_by_k;

 TotalCost_byScenario_K(ii, :) = Total_cost_by_k(:)';
 InfoCost_byScenario_K(ii, :) = Information_cost_by_k(:)';

 SOHLabelCost_byScenario_K(ii, :) = ...
 SOH_labelling_cost_by_k(:)';

 [Total_cost_min, idx_now] = min(Total_cost_by_k);

 opt_idx(ii) = idx_now;
 k_star(ii) = k_vals(idx_now);

 T1_star(ii) = T1_base(idx_now);
 T2_star(ii) = T2_base(idx_now);

 Opportunity_loss_USD(ii) = ...
 Fixed_Scale_N .* O_base(idx_now);

 Handling_rework_cost_USD(ii) = ...
 Fixed_Scale_N .* H_base(idx_now);

 Risk_penalty_USD(ii) = ...
 Fixed_Scale_N .* R_base(idx_now);

 Decision_loss_total_USD(ii) = ...
 Opportunity_loss_USD(ii) + ...
 Handling_rework_cost_USD(ii) + ...
 Risk_penalty_USD(ii);

 SOH_labelling_cost_USD(ii) = ...
 k_vals(idx_now) .* c_pack_now;

 Model_adaptation_cost_USD(ii) = c_train;

 Information_cost_USD(ii) = ...
 SOH_labelling_cost_USD(ii) + ...
 Model_adaptation_cost_USD(ii);

 Total_cost_USD(ii) = Total_cost_min;
 Cost_per_pack_USD(ii) = ...
 Total_cost_min ./ Fixed_Scale_N;

 Is_baseline_scenario(ii) = ...
 abs(c_pack_now - c_pack_baseline) <= 1e-12;

 Is_k_on_search_boundary(ii) = ...
 idx_now == 1 || idx_now == n_k;
end

if any(Is_k_on_search_boundary)

 warning(['At least one SOH-label cost scenario has k* on the evaluated ' ...
 'k boundary. Inspect the summary table before interpreting the ' ...
 'sensitivity trend.']);
end

%% 6) Build and save summary and all-k tables
Summary_Table = table( ...
 c_pack_list, ...
 Is_baseline_scenario, ...
 k_star, ...
 Is_k_on_search_boundary, ...
 T1_star, ...
 T2_star, ...
 Opportunity_loss_USD, ...
 Handling_rework_cost_USD, ...
 Risk_penalty_USD, ...
 Decision_loss_total_USD, ...
 SOH_labelling_cost_USD, ...
 Model_adaptation_cost_USD, ...
 Information_cost_USD, ...
 Total_cost_USD, ...
 Cost_per_pack_USD, ...
 'VariableNames', { ...
 'SOH_label_cost_USD_per_labelled_pack', ...
 'Is_baseline_scenario', ...
 'k_star', ...
 'Is_k_on_search_boundary', ...
 'T1_star', ...
 'T2_star', ...
 'Opportunity_loss_USD', ...
 'Mismatch_handling_rework_cost_USD', ...
 'Risk_penalty_USD', ...
 'Decision_loss_total_USD', ...
 'SOH_labelling_cost_USD', ...
 'Model_adaptation_cost_USD', ...
 'Information_cost_USD', ...
 'Total_cost_USD', ...
 'Total_cost_per_pack_USD'});

disp(' ');
disp('========== LFP SOH-label cost sensitivity ==========');
disp(Summary_Table);

writetable(Summary_Table, cfg.summary_csv);

% Long-format all-k table.
n_all = n_scenario .* n_k;

Scenario_index = repelem((1:n_scenario)', n_k);
SOH_label_cost_USD_per_labelled_pack = repelem(c_pack_list, n_k);
k_column = repmat(k_vals, n_scenario, 1);

T1_star_given_k = repmat(T1_base, n_scenario, 1);
T2_star_given_k = repmat(T2_base, n_scenario, 1);

Opportunity_loss_per_pack_USD = repmat(O_base, n_scenario, 1);
Mismatch_handling_rework_cost_per_pack_USD = repmat(H_base, n_scenario, 1);
Risk_penalty_per_pack_USD = repmat(R_base, n_scenario, 1);
Decision_loss_per_pack_USD = repmat(Decision_loss_per_pack, n_scenario, 1);

Opportunity_loss_total_USD = ...
 Fixed_Scale_N .* Opportunity_loss_per_pack_USD;

Mismatch_handling_rework_cost_total_USD = ...
 Fixed_Scale_N .* Mismatch_handling_rework_cost_per_pack_USD;

Risk_penalty_total_USD = ...
 Fixed_Scale_N .* Risk_penalty_per_pack_USD;

Decision_loss_total_all_k_USD = ...
 Fixed_Scale_N .* Decision_loss_per_pack_USD;

SOH_labelling_cost_all_k_USD = reshape( ...
 SOHLabelCost_byScenario_K', ...
 n_all, 1);

Model_adaptation_cost_all_k_USD = ...
 c_train .* ones(n_all, 1);

Information_cost_all_k_USD = reshape( ...
 InfoCost_byScenario_K', ...
 n_all, 1);

Total_cost_all_k_USD = reshape( ...
 TotalCost_byScenario_K', ...
 n_all, 1);

Total_cost_all_k_per_pack_USD = ...
 Total_cost_all_k_USD ./ Fixed_Scale_N;

Is_selected_k_star = false(n_all, 1);

for ii = 1:n_scenario

 row_start = (ii - 1) .* n_k + 1;
 row_end = ii .* n_k;

 scenario_rows = row_start:row_end;
 Is_selected_k_star(scenario_rows(opt_idx(ii))) = true;
end

AllK_Table = table( ...
 Scenario_index, ...
 SOH_label_cost_USD_per_labelled_pack, ...
 k_column, ...
 Is_selected_k_star, ...
 T1_star_given_k, ...
 T2_star_given_k, ...
 Opportunity_loss_per_pack_USD, ...
 Mismatch_handling_rework_cost_per_pack_USD, ...
 Risk_penalty_per_pack_USD, ...
 Decision_loss_per_pack_USD, ...
 Opportunity_loss_total_USD, ...
 Mismatch_handling_rework_cost_total_USD, ...
 Risk_penalty_total_USD, ...
 Decision_loss_total_all_k_USD, ...
 SOH_labelling_cost_all_k_USD, ...
 Model_adaptation_cost_all_k_USD, ...
 Information_cost_all_k_USD, ...
 Total_cost_all_k_USD, ...
 Total_cost_all_k_per_pack_USD, ...
 'VariableNames', { ...
 'Scenario_index', ...
 'SOH_label_cost_USD_per_labelled_pack', ...
 'k', ...
 'Is_selected_k_star', ...
 'T1_star_given_k', ...
 'T2_star_given_k', ...
 'Opportunity_loss_per_pack_USD', ...
 'Mismatch_handling_rework_cost_per_pack_USD', ...
 'Risk_penalty_per_pack_USD', ...
 'Decision_loss_per_pack_USD', ...
 'Opportunity_loss_total_USD', ...
 'Mismatch_handling_rework_cost_total_USD', ...
 'Risk_penalty_total_USD', ...
 'Decision_loss_total_USD', ...
 'SOH_labelling_cost_USD', ...
 'Model_adaptation_cost_USD', ...
 'Information_cost_USD', ...
 'Total_cost_USD', ...
 'Total_cost_per_pack_USD'});

writetable(AllK_Table, cfg.all_k_csv);

%% 7) Save the result MAT file
LFP_SOHLabelCostSensitivity_Result = struct();

LFP_SOHLabelCostSensitivity_Result.cfg = cfg;
LFP_SOHLabelCostSensitivity_Result.input_file = cfg.input_mat;
LFP_SOHLabelCostSensitivity_Result.input_type = cfg.input_type;

LFP_SOHLabelCostSensitivity_Result.Fixed_Scale_N = Fixed_Scale_N;
LFP_SOHLabelCostSensitivity_Result.c_train = c_train;
LFP_SOHLabelCostSensitivity_Result.c_pack_baseline = c_pack_baseline;

LFP_SOHLabelCostSensitivity_Result.k_vals = k_vals;
LFP_SOHLabelCostSensitivity_Result.O_base = O_base;
LFP_SOHLabelCostSensitivity_Result.H_base = H_base;
LFP_SOHLabelCostSensitivity_Result.R_base = R_base;

% Legacy alias for older downstream code.
LFP_SOHLabelCostSensitivity_Result.A_base = H_base;

LFP_SOHLabelCostSensitivity_Result.T1_base = T1_base;
LFP_SOHLabelCostSensitivity_Result.T2_base = T2_base;

LFP_SOHLabelCostSensitivity_Result.Decision_loss_per_pack = ...
 Decision_loss_per_pack;

LFP_SOHLabelCostSensitivity_Result.c_pack_list = c_pack_list;
LFP_SOHLabelCostSensitivity_Result.k_star = k_star;
LFP_SOHLabelCostSensitivity_Result.T1_star = T1_star;
LFP_SOHLabelCostSensitivity_Result.T2_star = T2_star;
LFP_SOHLabelCostSensitivity_Result.opt_idx = opt_idx;

LFP_SOHLabelCostSensitivity_Result.Opportunity_loss_USD = ...
 Opportunity_loss_USD;

LFP_SOHLabelCostSensitivity_Result.Handling_rework_cost_USD = ...
 Handling_rework_cost_USD;

LFP_SOHLabelCostSensitivity_Result.Risk_penalty_USD = ...
 Risk_penalty_USD;

LFP_SOHLabelCostSensitivity_Result.SOH_labelling_cost_USD = ...
 SOH_labelling_cost_USD;

LFP_SOHLabelCostSensitivity_Result.Model_adaptation_cost_USD = ...
 Model_adaptation_cost_USD;

LFP_SOHLabelCostSensitivity_Result.Information_cost_USD = ...
 Information_cost_USD;

LFP_SOHLabelCostSensitivity_Result.Total_cost_USD = ...
 Total_cost_USD;

LFP_SOHLabelCostSensitivity_Result.Cost_per_pack_USD = ...
 Cost_per_pack_USD;

LFP_SOHLabelCostSensitivity_Result.TotalCost_byScenario_K = ...
 TotalCost_byScenario_K;

LFP_SOHLabelCostSensitivity_Result.InfoCost_byScenario_K = ...
 InfoCost_byScenario_K;

LFP_SOHLabelCostSensitivity_Result.DecisionLoss_byScenario_K = ...
 DecisionLoss_byScenario_K;

LFP_SOHLabelCostSensitivity_Result.SOHLabelCost_byScenario_K = ...
 SOHLabelCost_byScenario_K;

LFP_SOHLabelCostSensitivity_Result.AdaptationCost_byScenario_K = ...
 AdaptationCost_byScenario_K;

LFP_SOHLabelCostSensitivity_Result.baseline_accounting_error = ...
 baseline_accounting_error;

LFP_SOHLabelCostSensitivity_Result.baseline_accounting_tolerance = ...
 baseline_accounting_tolerance;

LFP_SOHLabelCostSensitivity_Result.baseline_opt_k_rebuilt = ...
 baseline_opt_k_rebuilt;

LFP_SOHLabelCostSensitivity_Result.baseline_opt_k_loaded = ...
 baseline_opt_k_loaded;

LFP_SOHLabelCostSensitivity_Result.handling_field_used = ...
 handling_field_used;

LFP_SOHLabelCostSensitivity_Result.Summary_Table = Summary_Table;
LFP_SOHLabelCostSensitivity_Result.AllK_Table = AllK_Table;

save(cfg.result_mat, ...
 'LFP_SOHLabelCostSensitivity_Result', ...
 'Summary_Table', ...
 'AllK_Table', ...
 '-v7.3');

fprintf('Summary table saved: %s\n', cfg.summary_csv);
fprintf('All-k table saved: %s\n', cfg.all_k_csv);
fprintf('MAT result saved: %s\n', cfg.result_mat);

%% 8) Extended Data Fig. 6c: k* and cost per pack
fig_a = figure( ...
 'Name', 'ExD06c_LFP_SOH_label_cost_sensitivity', ...
 'Color', 'w', ...
 'Position', [100, 80, 820, 580]);

yyaxis left

h1 = plot( ...
 c_pack_list, ...
 k_star, ...
 '-o', ...
 'LineWidth', 2.0, ...
 'MarkerSize', 6.5, ...
 'MarkerFaceColor', 'w');

ylabel( ...
 'Optimal labelled target packs, k^*', ...
 'FontName', 'Arial', ...
 'FontSize', 11);

ylim([max(0, min(k_star) - 2), max(k_star) + 2]);

yyaxis right

h2 = plot( ...
 c_pack_list, ...
 Cost_per_pack_USD, ...
 '-s', ...
 'LineWidth', 2.0, ...
 'MarkerSize', 6.5, ...
 'MarkerFaceColor', 'w');

ylabel( ...
 'Total expected cost (USD per pack)', ...
 'FontName', 'Arial', ...
 'FontSize', 11);

hold on;

xline( ...
 c_pack_baseline, ...
 '--', ...
 'Baseline', ...
 'LabelVerticalAlignment', 'bottom', ...
 'LabelHorizontalAlignment', 'left', ...
 'LineWidth', 1.2, ...
 'Color', [0.35, 0.35, 0.35], ...
 'HandleVisibility', 'off');

grid on;
box on;

xlabel( ...
 'Unit SOH-label cost (USD per labelled pack)', ...
 'FontName', 'Arial', ...
 'FontSize', 11);

title( ...
 'Sensitivity of optimal information acquisition to SOH-label cost', ...
 'FontName', 'Arial', ...
 'FontSize', 11.5, ...
 'FontWeight', 'normal');

xlim([min(c_pack_list) - 0.04 .* range(c_pack_list), ...
 max(c_pack_list) + 0.04 .* range(c_pack_list)]);

legend( ...
 [h1, h2], ...
 {'Optimal k^*', 'Total expected cost per pack'}, ...
 'Location', 'best', ...
 'Box', 'off', ...
 'FontName', 'Arial', ...
 'FontSize', 9);

set(gca, ...
 'FontName', 'Arial', ...
 'FontSize', 10, ...
 'LineWidth', 1.0, ...
 'TickDir', 'out', ...
 'GridLineStyle', ':', ...
 'GridAlpha', 0.25);

local_save_figure( ...
 fig_a, ...
 cfg.fig_dual, ...
 cfg.png_dual, ...
 cfg.png_resolution);

%% 9) Extended Data Fig. 6d: optimized cost decomposition
fig_b = figure( ...
 'Name', 'ExD06d_LFP_SOH_label_cost_decomposition', ...
 'Color', 'w', ...
 'Position', [140, 100, 860, 580]);

Cost_Stack_1e4USD = [ ...
 Opportunity_loss_USD, ...
 Handling_rework_cost_USD, ...
 Risk_penalty_USD, ...
 SOH_labelling_cost_USD, ...
 Model_adaptation_cost_USD] ./ 1e4;

color_opp = [0.07, 0.39, 0.74];
color_handling = [0.36, 0.66, 0.93];
color_risk = [0.75, 0.85, 0.96];
color_label = [0.48, 0.29, 0.78];
color_adapt = [0.82, 0.72, 0.95];

hb = bar( ...
 c_pack_list, ...
 Cost_Stack_1e4USD, ...
 'stacked', ...
 'BarWidth', 0.78, ...
 'EdgeColor', 'none');

hold on;

set(hb(1), 'FaceColor', color_opp);
set(hb(2), 'FaceColor', color_handling);
set(hb(3), 'FaceColor', color_risk);
set(hb(4), 'FaceColor', color_label);
set(hb(5), 'FaceColor', color_adapt);

xline( ...
 c_pack_baseline, ...
 '--', ...
 'Baseline', ...
 'LabelVerticalAlignment', 'bottom', ...
 'LabelHorizontalAlignment', 'left', ...
 'LineWidth', 1.1, ...
 'Color', [0.35, 0.35, 0.35], ...
 'HandleVisibility', 'off');

grid on;
box on;

xlabel( ...
 'Unit SOH-label cost (USD per labelled pack)', ...
 'FontName', 'Arial', ...
 'FontSize', 11);

ylabel( ...
 'Optimized cost component (10^4 USD)', ...
 'FontName', 'Arial', ...
 'FontSize', 11);

title( ...
 'Cost decomposition at the optimized k^*', ...
 'FontName', 'Arial', ...
 'FontSize', 11.5, ...
 'FontWeight', 'normal');

xlim([min(c_pack_list) - 0.04 .* range(c_pack_list), ...
 max(c_pack_list) + 0.04 .* range(c_pack_list)]);

ymax = max(sum(Cost_Stack_1e4USD, 2));

if ~isfinite(ymax) || ymax <= 0
 ymax = 1;
end

ylim([0, ymax .* 1.08]);

legend( ...
 hb, ...
 {'Opportunity loss', ...
 'Mismatch handling and rework', ...
 'Risk penalty', ...
 'SOH labelling', ...
 'Model adaptation'}, ...
 'Location', 'northwest', ...
 'Box', 'off', ...
 'FontName', 'Arial', ...
 'FontSize', 8.2);

set(gca, ...
 'FontName', 'Arial', ...
 'FontSize', 10, ...
 'LineWidth', 1.0, ...
 'TickDir', 'out', ...
 'GridLineStyle', ':', ...
 'GridAlpha', 0.25);

local_save_figure( ...
 fig_b, ...
 cfg.fig_cost_decomp, ...
 cfg.png_cost_decomp, ...
 cfg.png_resolution);

fprintf('\n>>> Part4 Exp07 LFP SOH-label cost sensitivity completed.\n');
fprintf('>>> Output tables: %s\n', cfg.results_dir);
fprintf('>>> Figures: %s\n', cfg.extended_fig_dir);
fprintf('===============================================================================\n');

%% =========================================================================
% Local helper functions
%% =========================================================================

function [input_file, input_type] = local_select_input_file(cfg)
% Select the structured result and fall back to workspace/legacy files.

if isfile(cfg.input_result_primary)

 input_file = cfg.input_result_primary;
 input_type = 'structured_result';

elseif isfile(cfg.input_workspace_primary)

 input_file = cfg.input_workspace_primary;
 input_type = 'workspace';

elseif isfile(cfg.input_result_legacy)

 input_file = cfg.input_result_legacy;
 input_type = 'legacy_structured_result';

elseif isfile(cfg.input_workspace_legacy)

 input_file = cfg.input_workspace_legacy;
 input_type = 'legacy_workspace';

else

 error(['Fixed-scale LFP result or workspace file was not found.\n' ...
 'Checked:\n%s\n%s\n%s\n%s\n' ...
 'Run the Part4 Exp01 before running Exp07.'], ...
 cfg.input_result_primary, ...
 cfg.input_workspace_primary, ...
 cfg.input_result_legacy, ...
 cfg.input_workspace_legacy);
end
end

function local_require_fields(input_struct, required_fields, source_name)
% Verify that all required fields are available.

for ii = 1:numel(required_fields)

 field_now = required_fields{ii};

 if ~isfield(input_struct, field_now)

 error('Required field "%s" was not found in:\n%s', ...
 field_now, source_name);
 end
end
end

function [value, field_used] = local_get_first_existing_field( ...
 input_struct, candidate_fields, description)
% Return the first available preferred/legacy field.

value = [];
field_used = '';

for ii = 1:numel(candidate_fields)

 field_now = candidate_fields{ii};

 if isfield(input_struct, field_now)

 value = input_struct.(field_now);
 field_used = field_now;
 return;
 end
end

error('Required field for "%s" was not found. Checked: %s', ...
 description, strjoin(candidate_fields, ', '));
end

function local_save_figure(fig_handle, fig_file, png_file, resolution)
% Save a figure as both FIG and PNG files.

out_dir = fileparts(fig_file);

if ~exist(out_dir, 'dir')
 mkdir(out_dir);
end

savefig(fig_handle, fig_file);

exportgraphics( ...
 fig_handle, ...
 png_file, ...
 'Resolution', resolution);

fprintf('[Figure] Saved: %s\n', png_file);
end
